def utc_now_iso() -> str:
    return dt.datetime.now(dt.timezone.utc).isoformat()


def parse_time(s: Optional[str]) -> Optional[dt.datetime]:
    if not s:
        return None
    s = s.strip()
    if s.isdigit():
        return dt.datetime.fromtimestamp(int(s), tz=dt.timezone.utc)
    try:
        if s.endswith("Z"):
            s = s[:-1] + "+00:00"
        return dt.datetime.fromisoformat(s).astimezone(dt.timezone.utc)
    except Exception:
        raise ValueError(f"Invalid time format: {s}. Use ISO8601 (e.g. 2026-01-01T00:00:00Z) or epoch seconds.")


