def json_loads_stdin() -> Any:
    data = sys.stdin.read()
    if not data.strip():
        return None
    return json.loads(data)


def cmd_init(args: argparse.Namespace) -> None:
    es = get_es(args.es)
    ensure_index(es, args.docs_index, "docs")
