def cmd_index_doc(args: argparse.Namespace) -> None:
    es = get_es(args.es)
    ensure_index(es, args.index, "docs")
    doc = json.loads(args.document) if args.document else json_loads_stdin()
    if not isinstance(doc, dict):
        raise ValueError("Document must be a JSON object")
    resp = index_document(es, args.index, args.id, doc, refresh=args.refresh)
    print(json.dumps(resp))


def cmd_bulk_index_docs(args: argparse.Namespace) -> None:
    es = get_es(args.es)
    ensure_index(es, args.index, "docs")
    payload = json.loads(args.documents) if args.documents else json_loads_stdin()
    if not isinstance(payload, list):
        raise ValueError("Documents must be a JSON array of objects")
    resp = bulk_index(es, args.index, payload, id_field=args.id_field, refresh=args.refresh)
    print(json.dumps(resp))


def cmd_search_docs(args: argparse.Namespace) -> None:
    es = get_es(args.es)
    ensure_index(es, args.index, "docs")
    filters = json.loads(args.filters) if args.filters else None
    fields = args.fields.split(",") if args.fields else None
    resp = search_documents(
        es,
        args.index,
        args.query or "",
        fields=fields,
        filters=filters,
        from_=args.from_,
        size=args.size,
        sort=args.sort,
    )
    print(json.dumps(resp))


