    sp = sub.add_parser("search-logs", help="Search logs in logs index")
    sp.add_argument("--index", default=DEFAULT_INDEX_LOGS)
    sp.add_argument("--query", default=None)
    sp.add_argument("--level", default=None, help="Level or comma-separated levels")
