    sp.add_argument("--env", default=None, help="Env or comma-separated envs")
    sp.add_argument("--trace-id", default=None)
    sp.add_argument("--start", default=None, help="ISO8601 or epoch seconds")
    sp.add_argument("--end", default=None, help="ISO8601 or epoch seconds")
    sp.add_argument("--from", dest="from_", type=int, default=0)
    sp.add_argument("--size", type=int, default=50)
